
CREATE TABLE DEPARTAMENTO(
    ID INT PRIMARY KEY NOT NULL,
    NOMBRE TEXT NOT NULL
);

-- CREACION TABLA MUNICIPIO
CREATE TABLE MUNICIPIO(
    ID INT PRIMARY KEY NOT NULL,
    DEPARTAMENTO TEXT NOT NULL,
    MUNICIPIO TEXT NOT NULL
);

CREATE TABLE SI_NO(
    OPCION TEXT NOT NULL
);

CREATE TABLE ESTADO_OP(
    OPCION TEXT NOT NULL
);

-- CREACION TABLA SEXO
CREATE TABLE SEXO(
    OPCION TEXT NOT NULL
);

-- CREACION TABLA GRADOS
CREATE TABLE GRADOS(
    ID INT PRIMARY KEY NOT NULL,
    GRADO TEXT NOT NULL
);

-- CREACION TABLA COMANDO
CREATE TABLE COMANDO(
    ID INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    LINEA TEXT NOT NULL,
    TIPO_BATALLON_CDT TEXT
);

-- CREACION TABLA LINEA_OPERACION
CREATE TABLE LINEA_OPERACION(
    ID INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    OPERACION TEXT NOT NULL
);

-- CREACION TABLA OPERACIONES TERRESTRES UNIFICADAS
CREATE TABLE OPERACIONES_TERRESTRES_UNIFICADAS(
    ID INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    TAREA_UNIFICADA TEXT NOT NULL
);

-- CREACION TABLA Tareas_de_la_accion_decisiva_TTF
CREATE TABLE Tareas_de_la_accion_decisiva_TTF(
    ID INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    Tareas_de_la_accion_decisiva_TTF TEXT NOT NULL
);

-- CREACION TABLA OPERACIONES tarea
CREATE TABLE tarea(
    ID INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    Tareas_de_la_accion_decisiva_TTF TEXT NOT NULL,
    tarea TEXT NOT NULL
);

-- CREACION TABLA OPERACIONES TECNICAS_ACTIVIDADES
CREATE TABLE TECNICAS_ACTIVIDADES(
    ID INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    tarea TEXT NOT NULL,
    TECNICAS_ACTIVIDADES TEXT NOT NULL
);

-- CREACION TABLA OPERACIONES LATITUD
CREATE TABLE LATITUD(
    ID INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    LATITUD TEXT NOT NULL
);

-- CREACION TABLA OPERACIONES LONGITUD
CREATE TABLE LONGITUD(
    ID INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    LONGITUD TEXT NOT NULL
);

-- CREACION TABLA TIPO DE RESULTADOS
CREATE TABLE GRD(
    ID INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
    GRD TEXT NOT NULL
);

-- CREACION TABLA TIPO DE ESTADO_CODE
CREATE TABLE ESTADO_CODE(
    ESTADO_CODE TEXT NOT NULL
);

-- CREACION TABLA TIPO DE ORD_ESPECIAL
CREATE TABLE ORD_ESPECIAL(
    ORD_ESPECIAL TEXT NOT NULL
);

-- CREACION TABLA TIPO DE RELACION_DEL_MANDO
CREATE TABLE RELACION_DEL_MANDO(
    RELACION_DEL_MANDO TEXT NOT NULL
);

-- CREACION TABLA LINEAS DE PLAN inistop
CREATE TABLE LOO_LOEE(
    ID INT PRIMARY KEY NOT NULL,
    LINEA TEXT,
    EJC TEXT
);

-- CREACION TABLA efectivos UNIDAD
