-- =====================================================
-- TABLA: ROLES
-- =====================================================

CREATE TABLE IF NOT EXISTS roles (
    id SERIAL PRIMARY KEY,
    nombre VARCHAR(100) UNIQUE NOT NULL,
    descripcion TEXT
);

ON CONFLICT DO NOTHING;



-- =====================================================
-- TABLA: PAGINAS
-- =====================================================

CREATE TABLE IF NOT EXISTS paginas (
    id SERIAL PRIMARY KEY,
    nombre VARCHAR(150) UNIQUE NOT NULL,
    ruta VARCHAR(200) UNIQUE NOT NULL,
    descripcion TEXT,
    activa BOOLEAN DEFAULT TRUE,
    creada_en TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

ON CONFLICT DO NOTHING;



-- =====================================================
-- TABLA: GRADOS
-- =====================================================

CREATE TABLE IF NOT EXISTS grados (
    id SERIAL PRIMARY KEY,
    nombre VARCHAR(100) UNIQUE NOT NULL,
    abreviatura VARCHAR(20),
    nivel INTEGER NOT NULL
);

ALTER TABLE grados
ADD COLUMN IF NOT EXISTS nombre VARCHAR(100);

ALTER TABLE grados
ADD COLUMN IF NOT EXISTS abreviatura VARCHAR(20);

ALTER TABLE grados
ADD COLUMN IF NOT EXISTS nivel INTEGER;

DO $$
BEGIN
    IF EXISTS (
        SELECT 1
        FROM information_schema.columns
        WHERE table_name = 'grados'
        AND column_name = 'grado'
    ) THEN
        EXECUTE '
            UPDATE grados
            SET nombre = grado
            WHERE nombre IS NULL
            AND grado IS NOT NULL
        ';
    END IF;
END $$;

DO $$
BEGIN
    IF EXISTS (
        SELECT 1
        FROM information_schema.columns
        WHERE table_name = 'grados'
        AND column_name = 'grado'
    ) THEN
        ON CONFLICT (id) DO UPDATE
        SET grado = EXCLUDED.grado,
            nombre = EXCLUDED.nombre,
            abreviatura = EXCLUDED.abreviatura,
            nivel = EXCLUDED.nivel;
    ELSE
        ON CONFLICT (id) DO UPDATE
        SET nombre = EXCLUDED.nombre,
            abreviatura = EXCLUDED.abreviatura,
            nivel = EXCLUDED.nivel;
    END IF;
END $$;



-- =====================================================
-- TABLA: USUARIOS
-- =====================================================

CREATE TABLE IF NOT EXISTS usuarios (
    id SERIAL PRIMARY KEY,

    nombre_completo VARCHAR(200) NOT NULL,
    correo VARCHAR(150) UNIQUE NOT NULL,
    usuario VARCHAR(100) UNIQUE NOT NULL,
    password_hash TEXT NOT NULL,
    foto VARCHAR(255),

    grado_id INTEGER REFERENCES grados(id),
    nivel_unidad TEXT NOT NULL,
    unidad_usuario TEXT NOT NULL,

    activo BOOLEAN DEFAULT TRUE,
    creado_en TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- =====================================================
-- TABLA: USUARIO_ROL
-- =====================================================

CREATE TABLE IF NOT EXISTS usuario_rol (
    usuario_id INTEGER REFERENCES usuarios(id) ON DELETE CASCADE,
    rol_id INTEGER REFERENCES roles(id) ON DELETE CASCADE,
    PRIMARY KEY(usuario_id,rol_id)
);



-- =====================================================
-- TABLA: ROL_PAGINA
-- =====================================================

CREATE TABLE IF NOT EXISTS rol_pagina (
    rol_id INTEGER REFERENCES roles(id) ON DELETE CASCADE,
    pagina_id INTEGER REFERENCES paginas(id) ON DELETE CASCADE,

    tiene_permiso BOOLEAN DEFAULT TRUE,

    puede_ver BOOLEAN DEFAULT TRUE,
    puede_crear BOOLEAN DEFAULT FALSE,
    puede_editar BOOLEAN DEFAULT FALSE,
    puede_eliminar BOOLEAN DEFAULT FALSE,

    PRIMARY KEY(rol_id,pagina_id)
);



-- =====================================================
-- TABLA: USUARIO_PAGINA
-- =====================================================

CREATE TABLE IF NOT EXISTS usuario_pagina (
    usuario_id INTEGER REFERENCES usuarios(id) ON DELETE CASCADE,
    pagina_id INTEGER REFERENCES paginas(id) ON DELETE CASCADE,

    tiene_permiso BOOLEAN DEFAULT TRUE,

    puede_ver BOOLEAN DEFAULT TRUE,
    puede_crear BOOLEAN DEFAULT FALSE,
    puede_editar BOOLEAN DEFAULT FALSE,
    puede_eliminar BOOLEAN DEFAULT FALSE,

    PRIMARY KEY(usuario_id,pagina_id)
);



