-- =====================================================
-- INDICES
-- =====================================================

CREATE INDEX IF NOT EXISTS idx_usuario_login
ON usuarios(usuario,activo);

CREATE INDEX IF NOT EXISTS idx_usuario_rol
ON usuario_rol(usuario_id);

CREATE INDEX IF NOT EXISTS idx_rol_pagina
ON rol_pagina(rol_id);

CREATE INDEX IF NOT EXISTS idx_usuario_pagina
ON usuario_pagina(usuario_id);

CREATE TABLE IF NOT EXISTS personal_novedades (

    id SERIAL PRIMARY KEY,

    -- 🔹 Información básica
    grado VARCHAR(10),
    apellidos_nombres TEXT,
    cc BIGINT UNIQUE, -- 🔥 TABLA ACTUAL (último estado por cédula)

    -- 🔹 Organización militar
    division VARCHAR(10),
    brigada VARCHAR(10),
    batallon VARCHAR(50),
    compania VARCHAR(20),
    peloton INTEGER,

    relacion_mando VARCHAR(50),

    -- 🔹 Operación
    ciclo VARCHAR(50),
    actividad VARCHAR(100),

    -- 🔹 Detalle novedad
    ubicacion TEXT,
    cargo_especialidad TEXT,

    -- 🔹 Datos personales
    sexo VARCHAR(20),
    telefono BIGINT,
    rh VARCHAR(5),

    -- 🔹 Emergencia
    contacto_emergencia TEXT,
    telefono_emergencia BIGINT,
    parentesco VARCHAR(50),

    -- 🔹 Fechas
    fecha_inicio_novedad DATE,
    fecha_termino_novedad DATE,

    -- 🔹 Otros
    hijos INTEGER,
    estado_civil VARCHAR(50),
    escolaridad VARCHAR(100),

    correo_personal TEXT,
    correo_institucional TEXT,

    cursos_combte TEXT,

    actitud_psicofisica VARCHAR(50),
    porcentaje_discapacidad NUMERIC(5,2),
    fecha_informacion DATE,

    -- 🔥 Auditoría
    usuario_ingreso TEXT,
    nivel_unidad TEXT,
    unidad_usuario TEXT,
    fecha_creacion DATE DEFAULT CURRENT_DATE
);

CREATE TABLE IF NOT EXISTS personal_novedades_historial (

    id SERIAL PRIMARY KEY,

    grado VARCHAR(10),
    apellidos_nombres TEXT,
    cc BIGINT,

    division VARCHAR(10),
    brigada VARCHAR(10),
    batallon VARCHAR(50),
    compania VARCHAR(20),
    peloton INTEGER,

    relacion_mando VARCHAR(50),
    ciclo VARCHAR(50),
    actividad VARCHAR(100),
    ubicacion TEXT,
    cargo_especialidad TEXT,

    sexo VARCHAR(20),
    telefono BIGINT,
    rh VARCHAR(5),

    contacto_emergencia TEXT,
    telefono_emergencia BIGINT,
    parentesco VARCHAR(50),

    fecha_inicio_novedad DATE,
    fecha_termino_novedad DATE,

    hijos INTEGER,
    estado_civil VARCHAR(50),
    escolaridad VARCHAR(100),

    correo_personal TEXT,
    correo_institucional TEXT,
    cursos_combte TEXT,

    actitud_psicofisica VARCHAR(50),
    porcentaje_discapacidad NUMERIC(5,2),
    fecha_informacion DATE NOT NULL,

    usuario_ingreso TEXT,
    nivel_unidad TEXT,
    unidad_usuario TEXT,
    fecha_carga TIMESTAMP DEFAULT NOW()
);

CREATE UNIQUE INDEX IF NOT EXISTS ux_personal_hist_cc_fecha
ON personal_novedades_historial (cc, fecha_informacion);

CREATE INDEX IF NOT EXISTS idx_personal_hist_fecha
ON personal_novedades_historial (fecha_informacion);

CREATE INDEX IF NOT EXISTS idx_personal_hist_cc
ON personal_novedades_historial (cc);


CREATE TABLE IF NOT EXISTS armamento_general(
    id SERIAL PRIMARY KEY,
    tipo_armamento VARCHAR(50) NOT NULL,
    numero_serie VARCHAR(100) UNIQUE NOT NULL, -- 🔥 TABLA ACTUAL (último estado por serie)
    tipo_arma VARCHAR(50),
    calibre VARCHAR(20),
    estado VARCHAR(20),
    cant_provedores INTEGER,
    cantidad_municion INTEGER,
    division VARCHAR(50),
    brigada VARCHAR(50),
    batallon VARCHAR(50),
    compania VARCHAR(50),
    fecha_informacion DATE,

    -- 🔥 Auditoría
    usuario_ingreso TEXT,
    nivel_unidad TEXT,
    unidad_usuario TEXT,
    fecha_creacion DATE DEFAULT CURRENT_DATE
);

CREATE TABLE IF NOT EXISTS armamento_general_historial(
    id SERIAL PRIMARY KEY,
    tipo_armamento VARCHAR(50) NOT NULL,
    numero_serie VARCHAR(100) NOT NULL,
    tipo_arma VARCHAR(50),
    calibre VARCHAR(20),
    estado VARCHAR(20),
    cant_provedores INTEGER,
    cantidad_municion INTEGER,
    division VARCHAR(50),
    brigada VARCHAR(50),
    batallon VARCHAR(50),
    compania VARCHAR(50),
    fecha_informacion DATE NOT NULL,

    usuario_ingreso TEXT,
    nivel_unidad TEXT,
    unidad_usuario TEXT,
    fecha_carga TIMESTAMP DEFAULT NOW()
);

CREATE UNIQUE INDEX IF NOT EXISTS ux_armamento_general_hist_serie_fecha
ON armamento_general_historial (numero_serie, fecha_informacion);

CREATE INDEX IF NOT EXISTS idx_armamento_general_hist_fecha
ON armamento_general_historial (fecha_informacion);


CREATE TABLE IF NOT EXISTS armamento_asignado(
    id SERIAL PRIMARY KEY,

    -- 🔥 Relación actual activa/inactiva
    numero_serie VARCHAR(100) REFERENCES armamento_general(numero_serie) ON DELETE CASCADE,
    cc BIGINT REFERENCES personal_novedades(cc) ON DELETE CASCADE,

    fecha_informacion DATE,
    usuario_ingreso TEXT,
    nivel_unidad TEXT,
    unidad_usuario TEXT,
    fecha_carga TIMESTAMP DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS armamento_asignado_historial(
    id SERIAL PRIMARY KEY,
    numero_serie VARCHAR(100) NOT NULL,
    cc BIGINT NOT NULL,

    fecha_informacion DATE NOT NULL,
    usuario_ingreso TEXT,
    nivel_unidad TEXT,
    unidad_usuario TEXT,
    fecha_carga TIMESTAMP DEFAULT NOW()
);

CREATE UNIQUE INDEX IF NOT EXISTS ux_armamento_asignado_hist_relacion_fecha
ON armamento_asignado_historial (numero_serie, cc, fecha_informacion);
